// Input validation utilities
function sanitizeInput(input) {
    if (typeof input !== 'string') return '';
    // Remove potential injection characters for Cosmos DB SQL API
    return input.replace(/[;'"\\\/\x00-\x1f]/g, '').trim().substring(0, 256);
}

function validateQueryField(field) {
    return CONFIG.ALLOWED_QUERY_FIELDS.includes(field);
}

function validatePaginationToken(token) {
    if (!token) return null;
    if (typeof token !== 'string' || token.length > 4096) return null;
    // Cosmos DB continuation tokens are base64 encoded
    const base64Regex = /^[A-Za-z0-9+/=\-_]+$/;
    if (!base64Regex.test(token)) return null;
    return token;
}

function validateBatchSize(size) {
    const parsed = parseInt(size, 10);
    if (isNaN(parsed) || parsed < 1 || parsed > 2000) {
        return CONFIG.BATCH_SIZE;
    }
    return parsed;
}

// Secure Cosmos DB client initialization using Managed Identity
let cosmosClient = null;
let secretClient = null;

async function getCosmosClient() {
    if (cosmosClient) return cosmosClient;

    const credential = new DefaultAzureCredential();

    // Prefer Managed Identity (AAD) authentication - no keys needed
    if (CONFIG.COSMOS_ENDPOINT) {
        cosmosClient = new CosmosClient({
            endpoint: CONFIG.COSMOS_ENDPOINT,
            aadCredentials: credential,
            connectionPolicy: {
                requestTimeout: 30000,
                retryOptions: {
                    maxRetryAttemptCount: CONFIG.MAX_RETRIES,
                    fixedRetryIntervalInMilliseconds: 1000,
                    maxWaitTimeInSeconds: 30
                },
                enableEndpointDiscovery: true,
                preferredLocations: process.env.COSMOS_PREFERRED_REGIONS
                    ? process.env.COSMOS_PREFERRED_REGIONS.split(',').map(r => r.trim())
                    : undefined
            }
        });
    } else if (CONFIG.KEY_VAULT_URL) {
        // Fallback: retrieve connection string from Key Vault
        secretClient = new SecretClient(CONFIG.KEY_VAULT_URL, credential);
        const secret = await secretClient.getSecret('CosmosDBConnectionString');
        cosmosClient = new CosmosClient(secret.value);
    } else {
        throw new Error('No Cosmos DB configuration available. Set COSMOS_ENDPOINT or KEY_VAULT_URL.');
    }

    return cosmosClient;
}

// Processing checkpoint manager for resumable processing
class CheckpointManager {
    constructor(container) {
        this.container = container;
        this.checkpointDocId = 'batch-processing-checkpoint';
    }

    async saveCheckpoint(partitionKey, continuationToken, processedCount, batchId) {
        const checkpoint = {
            id: `${this.checkpointDocId}-${batchId}`,
            partitionKey: '_checkpoints',
            continuationToken,
            processedCount,
            lastUpdated: new Date().toISOString(),
            batchId,
            ttl: 86400 // Auto-expire after 24 hours
        };

        await this.container.items.upsert(checkpoint);
        return checkpoint;
    }

    async getCheckpoint(batchId) {
        try {
            const { resource } = await this.container
                .item(`${this.checkpointDocId}-${batchId}`, '_checkpoints')
                .read();
            return resource;
        } catch (error) {
            if (error.code === 404) return null;
            throw error;
        }
    }

    async clearCheckpoint(batchId) {
        try {
            await this.container
                .item(`${this.checkpointDocId}-${batchId}`, '_checkpoints')
                .delete();
        } catch (error) {
            if (error.code !== 404) throw error;
        }
    }
}

// Batch processor with graceful shutdown and progress tracking
class BatchProcessor {
    constructor(container, context) {
        this.container = container;
        this.context = context;
        this.processedCount = 0;
        this.errorCount = 0;
        this.startTime = Date.now();
        this.isShuttingDown = false;
        this.errors = [];
        this.checkpointManager = new CheckpointManager(container);
    }

    get elapsedMs() {
        return Date.now() - this.startTime;
    }

    get shouldStop() {
        return this.isShuttingDown || this.elapsedMs >= CONFIG.PROCESSING_TIMEOUT_MS;
    }

    requestShutdown(reason) {
        this.context.log(`Shutdown requested: ${reason}`);
        this.isShuttingDown = true;
    }

    async processItem(item) {
        // Validate item structure before processing
        if (!item || typeof item !== 'object' || !item.id) {
            throw new Error('Invalid item structure');
        }

        // --- Your business logic here ---
        // Example: transform, validate, enrich data
        const processedItem = {
            ...item,
            processedAt: new Date().toISOString(),
            processingVersion: '1.0',
            checksum: crypto
                .createHash('sha256')
                .update(JSON.stringify({ id: item.id, data: item.data }))
                .digest('hex')
        };

        // Write back processed result
        await this.container.items.upsert(processedItem);
        return processedItem;
    }

    async processBatch(items) {
        const results = { succeeded: 0, failed: 0, errors: [] };

        // Process items with controlled concurrency
        const chunks = [];
        for (let i = 0; i < items.length; i += CONFIG.MAX_CONCURRENT_BATCHES) {
            chunks.push(items.slice(i, i + CONFIG.MAX_CONCURRENT_BATCHES));
        }

        for (const chunk of chunks) {
            if (this.shouldStop) {
                this.context.log('Stopping batch processing due to time constraint');
                break;
            }

            const promises = chunk.map(async (item) => {
                try {
                    await this.processItem(item);
                    results.succeeded++;
                    this.processedCount++;
                } catch (error) {
                    results.failed++;
                    this.errorCount++;
                    const errorInfo = {
                        itemId: item.id,
                        error: error.message,
                        timestamp: new Date().toISOString()
                    };
                    results.errors.push(errorInfo);
                    this.errors.push(errorInfo);
                    this.context.log.error(`Failed to process item ${item.id}: ${error.message}`);
                }
            });

            await Promise.allSettled(promises);
        }

        return results;
    }

    async processAllWithCheckpoints(query, batchId) {
        const checkpoint = await this.checkpointManager.getCheckpoint(batchId);
        let continuationToken = checkpoint?.continuationToken || undefined;
        let totalProcessed = checkpoint?.processedCount || 0;

        this.context.log(`Starting batch ${batchId}. Resuming from ${totalProcessed} items.`);

        const querySpec = {
            query: query,
            parameters: []
        };

        let batchNumber = 0;

        while (!this.shouldStop) {
            batchNumber++;
            this.context.log(`Processing batch #${batchNumber}, total processed so far: ${totalProcessed}`);

            const { resources: items, continuationToken: nextToken } = await this.container.items
                .query(querySpec, {
                    maxItemCount: CONFIG.BATCH_SIZE,
                    continuationToken: continuationToken,
                    bufferItems: true,
                    maxDegreeOfParallelism: CONFIG.MAX_CONCURRENT_BATCHES
                })
                .fetchNext();

            if (!items || items.length === 0) {
                this.context.log('No more items to process');
                break;
            }

            const batchResult = await this.processBatch(items);
            totalProcessed += batchResult.succeeded;

            this.context.log(
                `Batch #${batchNumber} complete: ${batchResult.succeeded} succeeded, ${batchResult.failed} failed`
            );

            // Save checkpoint after each batch for resumability
            if (nextToken) {
                await this.checkpointManager.saveCheckpoint(
                    '_checkpoints',
                    nextToken,
                    totalProcessed,
                    batchId
                );
                continuationToken = nextToken;
            } else {
                // All items processed
                await this.checkpointManager.clearCheckpoint(batchId);
                break;
            }
        }

        if (this.shouldStop && continuationToken) {
            this.context.log(
                `Processing interrupted. Checkpoint saved at ${totalProcessed} items. Resume with batchId: ${batchId}`
            );
        }

        return {
            batchId,
            totalProcessed,
            errorCount: this.errorCount,
            completed: !this.shouldStop,
            elapsedMs: this.elapsedMs,
            errors: this.errors.slice(0, 50) // Limit error details in response
        };
    }
}

// Build a safe query from validated parameters
function buildQuery(filterField, filterValue, statusFilter) {
    let query = 'SELECT * FROM c';
    const conditions = [];

    if (filterField && filterValue) {
        if (!validateQueryField(filterField)) {
            throw new Error(`Invalid filter field: ${filterField}`);
        }
        const safeValue = sanitizeInput(filterValue);
        if (safeValue) {
            conditions.push(`c.${filterField} = "${safeValue}"`);
        }
    }

    if (statusFilter) {
        const safeStatus = sanitizeInput(statusFilter);
        const allowedStatuses = ['pending', 'processing', 'completed', 'failed', 'new'];
        if (allowedStatuses.includes(safeStatus)) {
            conditions.push(`c.status = "${safeStatus}"`);
        }
    }

    // Always exclude checkpoint documents
    conditions.push('NOT STARTSWITH(c.id, "batch-processing-checkpoint")');

    if (conditions.length > 0) {
        query += ' WHERE ' + conditions.join(' AND ');
    }

    if (query.length > CONFIG.MAX_QUERY_LENGTH) {
        throw new Error('Query exceeds maximum allowed length');
    }

    return query;
}

